class Solution {
public:
    bool digitCount(string num) {
        int n = num.length();
        for (int i = 0; i < n; i++) {
            char c = num[i];
            int count = 0;
            for (int j = 0; j < n; j++) {
                if (num[j] == c) count++;
            }
            if (count != (c - '0')) return false;
        }
        return true;
    }
};
```

